import React, { useState } from "react";
import classes from "../../assets/styles/login.module.css";
import { useNavigate } from 'react-router-dom';

export default function LoginPage() {
  const [isActive, setIsActive] = useState(false);
  const navigate = useNavigate();

  const openPopup = (url) => {
    const width = 500;
    const height = 600;
    const left = window.screen.width / 2 - width / 2;
    const top = window.screen.height / 2 - height / 2;
    
    window.open(
      url,
      'authPopup',
      `toolbar=no, location=no, directories=no, status=no, menubar=no, scrollbars=no, resizable=no, copyhistory=no, width=${width}, height=${height}, top=${top}, left=${left}`
    );
    return false;
  };

  const handleLogin = (e) => {
    e.preventDefault(); // Prevent form submission
    navigate('/Home');
  };

  const handleGuestClick = (e) => {
    e.preventDefault();
    navigate('/Home');
  };

  const handleRegisterClick = () => {
    setIsActive(true);
  };

  const handleLoginClick = () => {
    setIsActive(false);
  };

  const handleContainerNaming = () => {
    return isActive
      ? `${classes.container} ${classes.active}`
      : classes.container;
  };

  return (
    <div className={handleContainerNaming()} id="container">
      <div className={`${classes["form-container"]} ${classes["sign-up"]}`}>
        <form>
          <h1>צור חשבון</h1>
          <div className={classes.icons}>
            <a href="#" className="icon"><i className="fa-brands fa-google-plus-g"></i></a>
            <a href="#" className="icon"><i className="fa-brands fa-facebook-f"></i></a>
            <a href="#" className="icon"><i className="fa-brands fa-github"></i></a>
            <a href="#" className="icon"><i className="fa-brands fa-linkedin-in"></i></a>
          </div>
          <span>או הרשמ במייל</span>
          <input type="text" placeholder="שם" />
          <input type="email" placeholder="דוא" />
          <input type="password" placeholder="סיסמה" />
          <button type="button">להירשם</button>
        </form>
      </div>

      <div className={`${classes["form-container"]} ${classes["sign-in"]}`}>
        <form>
          <h1>להיכנס</h1>
          <div className={classes.icons}>
            <a href="https://accounts.google.com/signin" onClick={(e) => { e.preventDefault(); openPopup('https://accounts.google.com/signin'); }} className="icon"><i className="fa-brands fa-google-plus-g"></i></a>
            <a href="https://www.facebook.com/login" onClick={(e) => { e.preventDefault(); openPopup('https://www.facebook.com/login'); }} className="icon"><i className="fa-brands fa-facebook-f"></i></a>
            <a href="https://github.com/login" onClick={(e) => { e.preventDefault(); openPopup('https://github.com/login'); }} className="icon"><i className="fa-brands fa-github"></i></a>
            <a href="https://www.linkedin.com/login" onClick={(e) => { e.preventDefault(); openPopup('https://www.linkedin.com/login'); }} className="icon"><i className="fa-brands fa-linkedin-in"></i></a>
          </div>
          <span>או השתמש בסיסמת הדוא"ל שלך</span>
          <input type="email" placeholder="דוא" />
          <input type="password" placeholder="סיסמה" />
          <a href="/forgotPassword" className={classes.forgotPassword}>שכחת סיסמא?</a>
          <button type="button" onClick={handleLogin} className={classes.loginButton}>להיכנס</button>
          <span
            className={classes.guestLink}
            style={{ cursor: 'pointer', color: '#00f', textDecoration: 'underline', display: 'inline-block', marginTop: '1rem' }}
            onClick={handleGuestClick}
          >
            הכנס כאורח
          </span>
        </form>
      </div>

      <div className={classes.toggleContainer}>
        <div className={classes.toggle}>
          <div className={`${classes["togglePanel"]} ${classes["toggleLeft"]}`}>
            <h1> שלום, חבר!</h1>
            <p>רשום את הפרטים האישיים שלך,או</p>
            <button className={classes.hidden} id="login" onClick={handleLoginClick}>הכנס</button>
          </div>
          <div className={`${classes["togglePanel"]} ${classes["toggleRight"]}`}>
            <h1>!ברוך הבא</h1>
            <p>הכנס את הפרטים האישיים שלך,או</p>
            <button className={classes.hidden} id="register" onClick={handleRegisterClick}>הרשם</button>
          </div>
        </div>
      </div>
    </div>
  );
}
